import{$ as e,A as t,B as n,V as r}from"./chunks/framework.6NwDR3kH.js";var i=JSON.parse(`{"title":"食","description":"","frontmatter":{},"headers":[],"relativePath":"ccc/生活/食.md","filePath":"ccc/生活/食.md"}`),a={name:`ccc/生活/食.md`};function o(t,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[r(`<h1 id="食" tabindex="-1">食 <a class="header-anchor" href="#食" aria-label="Permalink to “食”">​</a></h1><h2 id="啤酒" tabindex="-1">啤酒 <a class="header-anchor" href="#啤酒" aria-label="Permalink to “啤酒”">​</a></h2><p><strong>酒精是一级致癌物</strong></p><p>白熊、福佳白、1664等比利时小麦，增味型的香气实质都是香精。如果完全靠投放陈皮、香菜籽，要达到其成品的香气，不易萃取，且成本太高，生产工艺上也比较麻烦。所以国产比利时小麦感觉香气很淡的，反而可能真的是靠投放陈皮香菜籽。</p><p>工业拉格，口感清冽反而存在难度，酒的发酵如果有缺陷，所谓精酿就可以东加西加，把味盖住，这也是为什么国产所谓精酿小厂雨后春笋一般冒出来，往往这些厂大概率是没有做好工业拉格的水平。</p><p>老骚友推荐，老骚友拒绝香料增味，独爱酒花，相对而言都是烈马。</p><blockquote><p>不一定上来就干烈马，麒麟一番榨季节限定，施耐德5号，鹅岛IPA，国产的如大九酿造、美西、黄河水，先试试水看看能不能接受酒花味。</p></blockquote><p>经典拉格：喜力、百威、青岛。</p><p>捷克皮尔森拉格、淡色拉格：乌奎尔</p><p>德式小麦：施耐德</p><p>兰比克啤酒（比利时）：Fruli芙力，</p><p>修道院啤酒：智美蓝帽（双料）粉象（双料三料）</p><p>经典IPA：内华达山脉</p><p>浑浊IPA：击倒巨人，僧侣（贵）</p><p>非老骚，也就是我：</p><p>雪花 黑狮 玫瑰红覆盆子果啤</p><p>西安七立稠酒 黑米黄酒 浙一家 米酒 醉金花 贵州醪糟</p><h2 id="咖啡" tabindex="-1">咖啡 <a class="header-anchor" href="#咖啡" aria-label="Permalink to “咖啡”">​</a></h2><p>用咖啡豆太麻烦了，我一般就是买瑞幸冻干咖啡粉，微酸，反正就那味呗，着重功能性。</p><p>云南省农业农村厅“2022年云南省精品咖啡庄园”：</p><p>天宇咖啡庄园 来珠克咖啡庄园 比顿咖啡庄园 佐园咖啡庄园 新寨咖啡庄园，电商同名。 高晟咖啡庄园 益嘉园咖啡庄园 粒述咖啡庄园 荣康达咖啡庄园</p><h2 id="杂" tabindex="-1">杂 <a class="header-anchor" href="#杂" aria-label="Permalink to “杂”">​</a></h2><p>味之素、鼎味泰，关东煮汤料</p>`,23)]])}var s=t(a,[[`render`,o]]);export{i as __pageData,s as default};